/* Aula 35 — modelJs: mini filtro (state -> render) */

const q = document.querySelector('#q');
const lista = document.querySelector('#lista');

const base = ['Ana', 'Bruno', 'Caio', 'Duda', 'Bia'];

let state = {
  items: base,
  query: ''
};

function render() {
  if (!lista) return;

  const term = state.query.trim().toLowerCase();
  const filtrado = term
    ? state.items.filter(x => x.toLowerCase().includes(term))
    : state.items;

  lista.innerHTML = '';
  for (const nome of filtrado) {
    const li = document.createElement('li');
    li.textContent = nome;
    lista.appendChild(li);
  }
}

function setQuery(v) {
  state.query = v;
  render();
}

if (q) {
  q.addEventListener('input', (e) => {
    setQuery(e.target.value);
  });
}

render();
